mapper.select:
SELECT p.id, CONCAT( CASE m.client_type WHEN 1 THEN 'admin' WHEN 2 THEN 'app' ELSE 'other' END, ':', m.module_key, ':', p.action_code ) AS permission_code, p.permission_desc, m.module_name, m.client_type FROM tb_permission p JOIN tb_module m ON p.module_id = m.id
p.is_delete = 0
AND permission_code LIKE CONCAT('%', #{permissionPageDTO.permissionCode}, '%')
AND m.id = #{permissionPageDTO.moduleId}
AND m.client_type = #{permissionPageDTO.clientType}
